        var reversed = reverse(slow!!.next)
        slow.next = null
        var curr = head

        while (curr != null && reversed != null) {
            val next = curr.next
            val revNext = reversed.next
            curr.next = reversed
            reversed.next = next
            curr = next
            reversed = revNext
        }
    }

